class Solution {
    public int numDecodings(String s) {
        if (s == null || s.isEmpty() || s.charAt(0) == '0') return 0;
        int n = s.length();
        int prev = 1, curr = 1;
        for (int i = 1; i < n; i++) {
            int temp = 0;
            if (s.charAt(i) != '0') temp = curr;
            int twoDigit = Integer.parseInt(s.substring(i - 1, i + 1));
            if (twoDigit >= 10 && twoDigit <= 26) {
                temp += prev;
            }
            prev = curr;
            curr = temp;
        }
        return curr;
    }
}
